import { NextResponse } from 'next/server';

/**
 * 说明：
 * 1) 只使用 Tavily 搜索 + 本地规则打分，不再依赖大模型，保证一定有内容可用。
 * 2) CEO 相关内容自动划入「巨头风向标」并默认为 must。
 * 3) 其他新闻根据 Tavily score + 时间衰减打 must / recommend / info 级别。
 */

type NewsLevel = 'must' | 'recommend' | 'info';

export type AiNewsItem = {
  level: NewsLevel;
  title: string;
  source: string;
  points: [string, string, string];
  url: string;
  date: string; // YYYY-MM-DD
  snippet?: string; // 原文摘要（可能是英文）
};

type ApiResponse = {
  generatedAt: string;
  executive: AiNewsItem[];
  feed: AiNewsItem[];
  message?: string;
};

// 识别 CEO 类新闻，用于前端分区展示
const CEO_HANDLES = [
  '@sama',
  '@sundarpichai',
  '@demishassabis',
  '@darioamodei',
  '@satyanadella',
  '@elonmusk',
  'sam altman',
  'sundar pichai',
  'demis hassabis',
  'dario amodei',
  'satya nadella',
  'elon musk',
];

// 搜索 1：主要 AI 公司 CEO 的最新动态（X/Twitter + 主流科技媒体）
const QUERY_CEO =
  '(sam altman OR sundar pichai OR dario amodei OR satya nadella OR elon musk) AI statement OR announcement';

// 搜索 2：AI 行业最近 3 天的重要事件（不限公司）
const QUERY_AI_GENERAL =
  'artificial intelligence AI major announcement model release breakthrough 2026';

type TavilyResult = {
  title?: string;
  url?: string;
  content?: string;
  snippet?: string;
  published_date?: string;
  score?: number;
  source?: string;
};

type TavilyPayload = {
  ceo_results?: TavilyResult[];
  general_results?: TavilyResult[];
};

/**
 * 双路并行 Tavily 搜索：
 * - CEO 追踪：针对关键人物动态
 * - 行业广搜：覆盖任意 AI 公司 / 研究机构，不限于固定几家
 */
async function fetchFromTavily(tavilyApiKey: string): Promise<TavilyPayload> {
  const base = {
    method: 'POST' as const,
    headers: { 'Content-Type': 'application/json' },
    cache: 'no-store' as RequestCache,
  };

  const [resCeo, resGeneral] = await Promise.all([
    fetch('https://api.tavily.com/search', {
      ...base,
      body: JSON.stringify({
        api_key: tavilyApiKey,
        query: QUERY_CEO,
        topic: 'news',
        search_depth: 'basic',
        max_results: 8,
        include_domains: ['x.com', 'twitter.com', 'techcrunch.com', 'theverge.com', 'wired.com'],
      }),
    }),
    fetch('https://api.tavily.com/search', {
      ...base,
      body: JSON.stringify({
        api_key: tavilyApiKey,
        query: QUERY_AI_GENERAL,
        topic: 'news',
        search_depth: 'basic',
        max_results: 20,
        include_domains: [
          'techcrunch.com',
          'theverge.com',
          'wired.com',
          'arstechnica.com',
          'venturebeat.com',
          'bloomberg.com',
          'reuters.com',
          'zdnet.com',
          'openai.com',
          'anthropic.com',
          'deepmind.google',
          'mistral.ai',
          'huggingface.co',
          'arxiv.org',
        ],
      }),
    }),
  ]);

  if (!resCeo.ok) {
    const t = await resCeo.text();
    throw new Error(`Tavily CEO 搜索失败(${resCeo.status}): ${t}`);
  }
  if (!resGeneral.ok) {
    const t = await resGeneral.text();
    throw new Error(`Tavily 行业搜索失败(${resGeneral.status}): ${t}`);
  }

  const [ceoData, generalData] = await Promise.all([resCeo.json(), resGeneral.json()]);

  return {
    ceo_results: ceoData?.results ?? [],
    general_results: generalData?.results ?? [],
  };
}

/**
 * 根据 Tavily 结果本地打分：
 * - 时间越近、score 越高、越像 CEO 动态 → level 越高
 */
function normalizeFromTavily(payload: TavilyPayload): AiNewsItem[] {
  const today = new Date();
  const all: TavilyResult[] = [
    ...(payload.ceo_results ?? []),
    ...(payload.general_results ?? []),
  ];

  const seen = new Set<string>();
  const items: { item: AiNewsItem; score: number }[] = [];

  for (const r of all) {
    const url = (r.url ?? '').trim();
    const title = (r.title ?? '').trim();
    if (!url || !title) continue;
    if (seen.has(url)) continue;
    seen.add(url);

    const snippet = (r.snippet ?? r.content ?? '').trim();
    const published = r.published_date ? new Date(r.published_date) : null;
    const days =
      published && !Number.isNaN(published.getTime())
        ? (today.getTime() - published.getTime()) / (1000 * 60 * 60 * 24)
        : 0;
    if (days > 3) continue;

    const host = safeHost(url);
    const rawSource = r.source ?? host;
    const source = rawSource.replace(/^www\./, '');
    const isCeo = isExecutiveByText(title, source);

    const baseScore = typeof r.score === 'number' ? r.score : 0;
    const recencyScore = Math.max(0, 1 - days / 3); // 0~1
    const ceoBonus = isCeo ? 0.7 : 0;
    const totalScore = baseScore + recencyScore + ceoBonus;

    let level: NewsLevel = 'info';
    if (isCeo || totalScore >= 1.4) {
      level = 'must';
    } else if (totalScore >= 0.8) {
      level = 'recommend';
    }

    const points = buildPointsFromSnippet(snippet || title);

    items.push({
      item: {
        level,
        title,
        source,
        points,
        url,
        date:
          published && !Number.isNaN(published.getTime())
            ? published.toISOString().slice(0, 10)
            : today.toISOString().slice(0, 10),
        snippet: snippet || undefined,
      },
      score: totalScore,
    });
  }

  // 按综合得分排序，让更重要的排在前面
  items.sort((a, b) => b.score - a.score);
  return items.map((x) => x.item);
}

function safeHost(url: string): string {
  try {
    return new URL(url).hostname;
  } catch {
    return 'unknown';
  }
}

function buildPointsFromSnippet(text: string): [string, string, string] {
  if (!text) {
    return ['暂无摘要', '暂无摘要', '暂无摘要'];
  }
  const clean = text.replace(/\s+/g, ' ').trim();
  const parts = clean
    .split(/。|\.|\?|！|!/g)
    .map((s) => s.trim())
    .filter(Boolean);

  const p1 = parts[0] ?? clean.slice(0, 60);
  const p2 = parts[1] ?? p1;
  const p3 = parts[2] ?? p2;
  return [p1, p2, p3];
}

function isExecutiveByText(title: string, source: string): boolean {
  const haystack = `${title} ${source}`.toLowerCase();
  return CEO_HANDLES.some((h) => haystack.includes(h.toLowerCase().replace('@', '')));
}

export async function GET() {
  try {
    const tavilyApiKey = process.env.TAVILY_API_KEY;

    if (!tavilyApiKey) {
      return NextResponse.json(
        {
          message: '缺少环境变量：TAVILY_API_KEY',
          generatedAt: new Date().toISOString(),
          executive: [],
          feed: [],
        },
        { status: 500 }
      );
    }

    const tavilyData = await fetchFromTavily(tavilyApiKey);
    const allNews = normalizeFromTavily(tavilyData);

    const executive = allNews
      .filter((item) => isExecutiveByText(item.title, item.source))
      .map((item) => ({ ...item, level: 'must' as const }));

    const feed = allNews
      .filter((item) => !isExecutiveByText(item.title, item.source))
      .sort((a, b) => {
        const weight: Record<NewsLevel, number> = { must: 0, recommend: 1, info: 2 };
        return weight[a.level] - weight[b.level];
      });

    const payload: ApiResponse = {
      generatedAt: new Date().toISOString(),
      executive,
      feed,
    };

    return NextResponse.json(payload, { status: 200 });
  } catch (error) {
    return NextResponse.json(
      {
        message: error instanceof Error ? error.message : '未知错误',
        generatedAt: new Date().toISOString(),
        executive: [],
        feed: [],
      },
      { status: 500 }
    );
  }
}
